import { useState, useEffect } from "react";
import "../assets/css/hero.css";
import heroConfig from "../conf/hero/config.json"; // importowanie pliku JSON

const HeroButton = () => {
  const [buttonText, setButtonText] = useState("Domyślny tekst");
  const [buttonHref, setButtonHref] = useState("#");

  useEffect(() => {
    console.log("Załadowane dane dla hero-button:", heroConfig);
    const section = heroConfig.find((item) => item["section-id"] === "hero-button");

    if (section) {
      setButtonText(section.text || "Domyślny tekst");
      setButtonHref(section.href || "#");
    }
  }, []);

  return (
    <a href={buttonHref} className="hero-button-link">
      <button className="hero-button">{buttonText}</button> {/* wyświetlenie tekstu na przycisku */}
    </a>
  );
};

export default HeroButton;
